import { randomUUID } from "node:crypto";

const port = Number(Bun.env.PORT ?? 3000);

type Payment = { id: string; amount: number; currency: string; status: "captured" };
type StoredResponse = { fingerprint: string; payment: Payment };

const payments = new Map<string, Payment>();
// Per-key record of the first completed capture.
const byKey = new Map<string, StoredResponse>();
// Per-key in-flight promise so concurrent identical requests collapse into one.
const inFlight = new Map<string, Promise<StoredResponse>>();

function fingerprint(amount: number, currency: string): string {
  return JSON.stringify({ amount, currency });
}

function paymentBody(p: Payment) {
  return { id: p.id, amount: p.amount, currency: p.currency, status: p.status };
}

Bun.serve({
  port,
  async fetch(request) {
    const url = new URL(request.url);
    const segments = url.pathname.split("/").filter(Boolean);

    if (request.method === "GET" && url.pathname === "/healthz") {
      return Response.json({ ok: true }, { status: 200 });
    }

    if (request.method === "POST" && url.pathname === "/payments") {
      const key = request.headers.get("idempotency-key");
      if (key === null || key.trim() === "") {
        return Response.json({ error: "missing_idempotency_key" }, { status: 400 });
      }

      let body: unknown;
      try {
        body = await request.json();
      } catch {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }
      const record = body as Record<string, unknown> | null;
      const amount = record?.amount;
      const currency = record?.currency;
      if (
        typeof amount !== "number" ||
        !Number.isInteger(amount) ||
        amount <= 0 ||
        typeof currency !== "string"
      ) {
        return Response.json({ error: "invalid_body" }, { status: 422 });
      }

      const fp = fingerprint(amount, currency);

      // Fast path: a prior capture already completed for this key.
      const existing = byKey.get(key);
      if (existing) {
        if (existing.fingerprint !== fp) {
          return Response.json({ error: "idempotency_key_reuse" }, { status: 409 });
        }
        return Response.json(paymentBody(existing.payment), {
          status: 201,
          headers: { "Idempotency-Replayed": "true" },
        });
      }

      // Concurrency: serialize per key via an in-flight promise so a burst of
      // identical requests produces exactly one payment. Exactly one request
      // installs the promise (the creator); the rest join it (replays).
      let isCreator = false;
      let pending = inFlight.get(key);
      if (!pending) {
        isCreator = true;
        pending = (async () => {
          const payment: Payment = {
            id: randomUUID(),
            amount,
            currency,
            status: "captured",
          };
          payments.set(payment.id, payment);
          const stored: StoredResponse = { fingerprint: fp, payment };
          byKey.set(key, stored);
          return stored;
        })();
        inFlight.set(key, pending);
        pending.finally(() => {
          if (inFlight.get(key) === pending) inFlight.delete(key);
        });
      }

      const stored = await pending;
      if (stored.fingerprint !== fp) {
        // The winning request for this key used a different body.
        return Response.json({ error: "idempotency_key_reuse" }, { status: 409 });
      }
      // The creator returns a fresh 201; everyone who joined is a replay.
      const headers = isCreator ? {} : { "Idempotency-Replayed": "true" };
      return Response.json(paymentBody(stored.payment), { status: 201, headers });
    }

    if (segments.length === 2 && segments[0] === "payments" && request.method === "GET") {
      const payment = payments.get(segments[1]);
      if (!payment) return Response.json({ error: "not_found" }, { status: 404 });
      return Response.json(paymentBody(payment), { status: 200 });
    }

    return Response.json({ error: "not_found" }, { status: 404 });
  },
});

console.log(`payment-capture reference listening on ${port}`);
BUN_BENCH_SOLUTION_EOF
